        def __init__(self):
            self._total = _TEST_SIZE
            self._pos = 0
        def read(self, n=-1):
            if n == -1:
                remaining = self._total - self._pos
                self._pos = self._total
                return b"x" * remaining
            chunk = min(n, self._total - self._pos)
            self._pos += chunk
            return b"x" * chunk
        def seek(self, pos, whence=0):
            if whence == 0:
                self._pos = pos
            elif whence == 2:
